// Main App component for secure file sharing
import React, { useState, useEffect } from 'react';
import Upload from './Upload';
import Download from './Download';
import './App.css';

function App() {
    const [files, setFiles] = useState([]);
    const [activeTab, setActiveTab] = useState('upload');

    useEffect(() => {
        fetchFiles();
    }, []);

    const fetchFiles = async () => {
        try {
            const response = await fetch('http://localhost:5000/api/files/list');
            if (!response.ok) {
                throw new Error('Failed to fetch files');
            }
            const data = await response.json();
            setFiles(Array.isArray(data) ? data : []);
        } catch (error) {
            console.error('Error fetching files:', error);
            setFiles([]);
        }
    };

    const handleUploadSuccess = () => {
        fetchFiles();
        setActiveTab('download');
    };

    return (
        <div className="App">
            <header className="App-header">
                <h1>Secure File Share</h1>
                <p>Upload and download files with encryption</p>
            </header>
            
            <main>
                <div className="tabs">
                    <button 
                        className={activeTab === 'upload' ? 'active' : ''}
                        onClick={() => setActiveTab('upload')}
                    >
                        Upload
                    </button>
                    <button 
                        className={activeTab === 'download' ? 'active' : ''}
                        onClick={() => setActiveTab('download')}
                    >
                        Download
                    </button>
                </div>

                {activeTab === 'upload' && (
                    <Upload onUploadSuccess={handleUploadSuccess} />
                )}
                
                {activeTab === 'download' && (
                    <Download files={files} onFileChange={fetchFiles} />
                )}
            </main>
        </div>
    );
}

export default App;
